// Generate social post content using Claude API
const store   = $json.store || 'HOO';
const section = $json.section || 'hero section';
const before  = $json.before_img || '';
const after   = $json.after_img || '';
const type    = $json.client_type || 'local business';
const headline = $json.headline || 'built a website for a local business';

// Build the prompt for Claude
const systemPrompt = `You are the social media voice for HOO (herrmanonlineoutlook.com). 
HOO is run by Matthew Herrman — a blue collar builder from Independence MO who learned AI and now builds premium Shopify websites for free. Clients pay only if they love it.
Voice: raw, real, blue collar pride. No corporate fluff. Short sentences. Builder energy.
Mission: helping local businesses get online and compete.`;

const userPrompt = `Write 3 social media posts for this build:
- Store: ${store}
- What was built: ${section}
- Client type: ${type}
- Headline: ${headline}

Post 1: Facebook (3-4 sentences, conversational, local small business owners as audience)
Post 2: Instagram (shorter, punchy, with 5 relevant hashtags)
Post 3: TikTok caption (1-2 sentences max, hook first)

Each post should end with: herrmanonlineoutlook.com
Always mention the "build free, pay on approval" model somewhere.
Return as JSON: { facebook: string, instagram: string, tiktok: string }`;

return [{ json: { systemPrompt, userPrompt, store, section, before, after, type, headline } }];

// Parse Claude response and prepare social queue data — sandbox safe (no fs)
const content = $json.body?.content?.[0]?.text || '';
let captions;
try {
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  captions = jsonMatch ? JSON.parse(jsonMatch[0]) : { facebook: content, instagram: content, tiktok: content };
} catch {
  captions = { facebook: content, instagram: content, tiktok: content };
}

const today = new Date().toISOString().split('T')[0];
const slug  = ($json.section || 'build').toLowerCase().replace(/\s+/g, '-');
const fname = `SOCIAL-${today}-${slug}.json`;

const post = {
  date:      today,
  store:     $json.store,
  section:   $json.section,
  type:      $json.type,
  before:    $json.before,
  after:     $json.after,
  captions,
  status:    'queued',
  filename:  fname
};

return [{ json: { saved: true, filename: fname, captions, post: JSON.stringify(post, null, 2) } }];

